/* Subset hand-drawn fonts (Caveat 400/700, Patrick Hand, Ma Shan Zheng) as base64 woff2, for PNG/PDF export where the webview blocks the Google Fonts fetch. Regenerate via the subset script if pages add new characters. */
window.BOOK_FONTS="@font-face{font-family:'Caveat';font-style:normal;font-weight:400;src:url(data:font/woff2;base64,) format('woff2');}@font-face{font-family:'Caveat';font-style:normal;font-weight:700;src:url(data:font/woff2;base64,) format('woff2');}@font-face{font-family:'Patrick Hand';font-style:normal;font-weight:400;src:url(data:font/woff2;base64,) format('woff2');}@font-face{font-family:'Ma Shan Zheng';font-style:normal;font-weight:400;src:url(data:font/woff2;base64,) format('woff2');}";
